function wpbp_cached_flag(): bool {
    $cached = wp_cache_get( 'flag', 'wpbp-cache-flag', false, $found );
    if ( $found ) {
        return (bool) $cached;
    }
    // Simulate expensive computation that yields false first time.
    $value = false;
    wp_cache_set( 'flag', $value, 'wpbp-cache-flag' );
    return $value;
}

function wpbp_get_options_cached( array $keys ): array {
    $group = 'wpbp-options';
    $fetched = wp_cache_get_multiple( $keys, $group );
    $misses  = array();
    foreach ( $keys as $k ) {
        if ( ! array_key_exists( $k, $fetched ) ) {
            $misses[] = $k;
        }
    }
    if ( $misses ) {
        $fill = array();
        foreach ( $misses as $k ) {
            $val       = get_option( $k, null );
            $fill[ $k ] = $val;
            $fetched[ $k ] = $val;
        }
        wp_cache_set_multiple( $fill, $group );
    }
    return $fetched;
}
